const webhookData = $('Webhook Trigger').first().json;
const b = webhookData.body ?? webhookData;
const run_id = b.run_id || b.runId || b.runID;
const query = b.enforced_query || b.query || b.enforcedQuery;
const max_results = Number(b.max_results ?? b.maxResults ?? 30);
if (!run_id || !query) {
  return [{ json: { ok:false, error:{code:'MISSING_FIELDS', message:'run_id and enforced_query are required'}, run_id: run_id ?? null, query: query ?? null, max_results } }];
}
return [{ json: { ok:true, run_id, query, max_results: Math.max(1, Math.min(30, max_results)), scope: b.scope ?? null, metro: b.metro ?? null, role_focus: b.role_focus ?? null } }];

const ni = $('Normalize Input').first().json;
const base = ni.query;
const run_id = ni.run_id;
const FIRECRAWL_LIMIT = 15;
const neg = ' -jobs -job -careers -career -hiring -apply -"job board" -indeed -ziprecruiter -glassdoor -linkedin.com/jobs';
const q1 = base + neg;
const q2 = q1 + ' (staff OR team OR leadership OR "about us" OR "our people" OR board)';
const q3 = q1 + ' (leadership OR "executive team" OR "board of directors")';
const q4 = q1 + ' (directory OR "staff directory" OR "our team" OR "meet the team")';
return [
  { json: { run_id, query_variant: 'base', query: q1, limit: FIRECRAWL_LIMIT } },
  { json: { run_id, query_variant: 'directory', query: q2, limit: FIRECRAWL_LIMIT } },
  { json: { run_id, query_variant: 'leadership', query: q3, limit: FIRECRAWL_LIMIT } },
  { json: { run_id, query_variant: 'team_page', query: q4, limit: FIRECRAWL_LIMIT } }
];

const ni = $('Normalize Input').first().json;
const run_id = ni.run_id;
const allItems = $input.all();
const queryItems = $('Build Queries').all();

const blockedUrlPatterns = [
  /indeed\.com/i, /glassdoor\.com/i, /linkedin\.com\/jobs/i,
  /ziprecruiter\.com/i, /workday\.com/i, /lever\.co/i,
  /greenhouse\.io/i, /careers\./i, /\/jobs\//i, /\/careers\//i,
  /\/job\//i, /\/hiring/i
];
const blockedContentKeywords = [
  'apply now', 'job posting', 'job description', 'we are hiring',
  'open position', 'career opportunities', 'submit your resume',
  'equal opportunity employer'
];

const BUCKET_CAP = 25;
const FINAL_CAP = 30;
const variants = ['base', 'directory', 'leadership', 'team_page'];

const buckets = {};
for (const v of variants) buckets[v] = [];
for (let i = 0; i < allItems.length; i++) {
  const d = allItems[i].json;
  const variant = (queryItems[i] && queryItems[i].json.query_variant) || 'base';
  const arr = d.data || d.results || (d.body && (d.body.data || d.body.results)) || [];
  if (Array.isArray(arr)) {
    for (const r of arr) {
      if (!buckets[variant]) buckets[variant] = [];
      buckets[variant].push(r);
    }
  }
}

let filtered_out = 0;
const globalSeen = new Set();

function canonicalUrl(url) {
  try {
    let u = url.toLowerCase().split('?')[0].split('#')[0];
    u = u.replace(/^https?:\/\/www\./, 'https://');
    u = u.replace(/\/$/, '');
    return u;
  } catch(e) { return url.toLowerCase(); }
}

function filterBucket(items, variantLabel) {
  const out = [];
  for (const r of items) {
    const url = (r.url || r.link || r.source_url || '').trim();
    const title = (r.title || r.name || r.pageTitle || '').trim();
    const snippet = (r.description || r.snippet || r.text || r.summary || '').trim();
    const combined = (title + ' ' + snippet).toLowerCase();
    if (url && blockedUrlPatterns.some(p => p.test(url))) { filtered_out++; continue; }
    if (blockedContentKeywords.some(kw => combined.includes(kw))) { filtered_out++; continue; }
    const canonical = canonicalUrl(url);
    if (canonical && globalSeen.has(canonical)) { filtered_out++; continue; }
    if (canonical) globalSeen.add(canonical);
    out.push({ title, url, snippet, query_variant: variantLabel });
  }
  return out;
}

const candidateBuckets = {};
for (const v of variants) {
  candidateBuckets[v] = filterBucket(buckets[v] || [], v).slice(0, BUCKET_CAP);
}

const merged = [];
const finalSeen = new Set();
const pointers = {};
for (const v of variants) pointers[v] = 0;
let progress = true;
while (merged.length < FINAL_CAP && progress) {
  progress = false;
  for (const v of variants) {
    if (merged.length >= FINAL_CAP) break;
    while (pointers[v] < candidateBuckets[v].length) {
      const r = candidateBuckets[v][pointers[v]];
      pointers[v]++;
      const canonical = canonicalUrl(r.url);
      if (canonical && finalSeen.has(canonical)) continue;
      if (canonical) finalSeen.add(canonical);
      merged.push(r);
      progress = true;
      break;
    }
  }
}

return [{ json: { run_id, filtered_results: merged, filtered_out_count: filtered_out, has_results: merged.length > 0 } }];

const prev = $('Merge & Pre-Filter').first().json;
const run_id = prev.run_id;
const results = prev.filtered_results || [];

const preferredPatterns = [
  /\/about/i, /\/team/i, /\/leadership/i, /\/staff/i,
  /\/board/i, /\/our-people/i, /\/who-we-are/i,
  /\/people/i, /\/directors/i, /\/management/i
];

const scored = results.map(r => {
  const url = r.url || '';
  const bonus = preferredPatterns.some(p => p.test(url)) ? 100 : 0;
  return { ...r, score: bonus };
});

scored.sort((a, b) => b.score - a.score);
const topK = scored.slice(0, 8);

return topK.map(r => ({ json: { run_id, url: r.url, title: r.title || '', snippet: r.snippet || '' } }));

const allItems = $input.all();
const ni = $('Normalize Input').first().json;
const run_id = ni.run_id;
const query = ni.query;
const CAP = 16000;

let scraped_context = 'Query: ' + query + '\n\n';
let charCount = scraped_context.length;
let scrape_ok = 0;
let scrape_fail = 0;

for (const item of allItems) {
  const d = item.json;
  const text = d?.data?.markdown || d?.data?.content || d?.data?.text ||
               d?.markdown || d?.content || d?.text ||
               d?.body?.data?.markdown || d?.body?.data?.content || '';
  const url = d?.data?.metadata?.sourceURL || d?.url || d?.data?.url || '';
  const title = d?.data?.metadata?.title || d?.title || '';

  if (!text || String(text).trim().length < 50) {
    scrape_fail++;
    const snippet = d?.snippet || '';
    if (snippet) {
      const entry = '--- Source: ' + url + ' ---\n' + (title ? title + '\n' : '') + snippet + '\n\n';
      if (charCount + entry.length <= CAP) {
        scraped_context += entry;
        charCount += entry.length;
      }
    }
    continue;
  }

  scrape_ok++;
  const trimmed = String(text).trim().slice(0, 2500);
  const entry = '--- Source: ' + url + ' ---\n' + (title ? title + '\n' : '') + trimmed + '\n\n';
  if (charCount + entry.length > CAP) {
    const remaining = CAP - charCount - 100;
    if (remaining > 200) {
      scraped_context += '--- Source: ' + url + ' ---\n' + trimmed.slice(0, remaining) + '\n[truncated]\n\n';
    }
    break;
  }
  scraped_context += entry;
  charCount += entry.length;
}

return [{ json: { run_id, query, scraped_context, meta: { scrape_ok, scrape_fail, scrape_failed: scrape_ok === 0 } } }];

const merged = $('Merge Scrapes to Context').first().json;
const run_id = merged.run_id;
const query = merged.query;
let search_context = merged.scraped_context || '';

// Always append the full filtered_results list (30 items) so the LLM sees all of them
const prev = $('Merge & Pre-Filter').first().json;
const results = prev.filtered_results || [];
const CAP = 16000;
const FULL_DETAIL_LIMIT = 20;

if (!search_context || search_context.length < 100) {
  search_context = 'Query: ' + query + '\n\n';
}

search_context += '\n--- ALL SEARCH RESULTS ---\n';
let charCount = search_context.length;
for (let i = 0; i < results.length; i++) {
  const r = results[i];
  let entry;
  if (i < FULL_DETAIL_LIMIT) {
    entry = (i+1) + '. ' + (r.title ?? '') + '\nURL: ' + (r.url ?? '') + '\nSnippet: ' + (r.snippet ?? '');
  } else {
    entry = (i+1) + '. ' + (r.title ?? '') + '\nURL: ' + (r.url ?? '');
  }
  if (charCount + entry.length + 2 > CAP) break;
  search_context += entry + '\n\n';
  charCount += entry.length + 2;
}

return [{ json: { run_id, query, search_context } }];

let txt = $('LLM Extract People From Results').first().json?.choices?.[0]?.message?.content ?? '';
txt = String(txt).trim();
let parsed;
try { parsed = JSON.parse(txt); } catch(e) {
  const m = txt.match(/\[[\s\S]*\]/);
  if (m) parsed = JSON.parse(m[0]); else parsed = [];
}
const people = Array.isArray(parsed) ? parsed : (parsed.people || []);
const ni = $('Normalize Input').first().json;
const run_id = ni.run_id;
const scrapeMeta = $('Merge Scrapes to Context').first().json.meta || {};
const cleaned = people.map(p => ({
  title: (p.name ?? 'Unknown') + (p.title ? ' - ' + p.title : ''),
  description: p.evidence ?? null,
  url: p.source_url ?? p.url ?? null,
  source: 'firecrawl+llm',
  organization: p.organization_name ?? p.organization ?? null,
  contact_name: p.name ?? null,
  contact_email: p.email ?? null,
  contact_phone: p.phone ?? null,
  confidence: (typeof p.confidence === 'number') ? p.confidence : null,
  raw_data: p
}));

// Parse brief
let brief = null;
try {
  const briefTxt = $('LLM Build Search Brief').first().json?.choices?.[0]?.message?.content ?? '';
  if (briefTxt.trim()) brief = JSON.parse(briefTxt.trim());
} catch(e) { brief = null; }

// Reconcile brief summary with actual parsed result count
if (brief && brief.summary) {
  const actualCount = cleaned.length;
  brief.summary = brief.summary.replace(/\b\d+\s+(people|contacts?|results?|items?|individuals?)\b/gi, actualCount + ' $1');
}

return [{ json: { run_id, status: 'completed', results: cleaned, brief, meta: { micro_crawl: true, scrape_ok: scrapeMeta.scrape_ok ?? 0, scrape_fail: scrapeMeta.scrape_fail ?? 0 } } }];

const run_id = $('Normalize Input').first().json.run_id;
const filtered_out = $('Merge & Pre-Filter').first().json.filtered_out_count || 0;
return [{ json: { run_id, status: 'completed', results: [], brief: null, meta: { filtered_out: true, filtered_out_count: filtered_out } } }];
